@router.post("/sessions/{session_id}/close")
async def close_session_on_client_exit(session_id: str, reason: str = "tab_close"):
    """Mark a session completed when the client tab/app is closed."""
    try:
        from app.api.websocket import shutdown_active_session_handler

        await shutdown_active_session_handler(session_id, reason=reason or "tab_close")

        session = await firestore_service.get_session(session_id)
        if not session:
            raise HTTPException(status_code=status.HTTP_404_NOT_FOUND, detail="Session not found")

        close_metadata = {
            "closed_by_client": True,
            "close_reason": (reason or "tab_close")[:80],
            "closed_at": datetime.utcnow().isoformat(),
        }

        # Re-read before persisting so we don't clobber a concurrent case assignment
        # or other report updates that landed immediately before unload.
        latest_session = await firestore_service.get_session(session_id) or session

        if _is_empty_session_noise(latest_session):
            await firestore_service.delete_session(session_id)
            await storage_service.delete_session_files(session_id)
            remove_agent(session_id)
            return {
                "closed": True,
                "deleted_empty_session": True,
                "session_id": session_id,
                "status": "deleted",
                "case_id": None,
            }

        metadata = dict(latest_session.metadata or {})
        metadata.update(close_metadata)
        latest_session.metadata = metadata

        if latest_session.status == "active":
            latest_session.status = "completed"

        latest_session.updated_at = datetime.utcnow()

        success = await firestore_service.update_session(latest_session)
        if not success:
            raise HTTPException(
                status_code=status.HTTP_500_INTERNAL_SERVER_ERROR,
                detail="Failed to close session",
            )

        remove_agent(session_id)
        return {
            "closed": True,
            "session_id": session_id,
            "status": latest_session.status,
            "case_id": latest_session.case_id,
        }

    except HTTPException:
        raise
    except Exception as e:
        logger.error(f"Error closing session {session_id}: {e}")
        raise HTTPException(
            status_code=status.HTTP_500_INTERNAL_SERVER_ERROR,
            detail="Failed to close session",
        )



