# ── Witness Credibility Scorecard ───────────────────
@router.get("/sessions/{session_id}/credibility-report")
async def credibility_report(session_id: str):
    """Comprehensive credibility assessment combining multiple factors."""
    session = await firestore_service.get_session(session_id)
    if not session:
        raise HTTPException(status_code=404, detail="Session not found")

    statements = []
    if hasattr(session, "messages"):
        for m in session.messages:
            role = m.get("role", "") if isinstance(m, dict) else getattr(m, "role", "")
            content = m.get("content", "") if isinstance(m, dict) else getattr(m, "content", "")
            if role == "user" and len(content) > 20:
                statements.append(content)

    text = " ".join(statements).lower()
    words = text.split()
    total_words = len(words)

    # Certainty language
    certain_words = ["definitely", "certainly", "absolutely", "clearly", "obviously", "sure", "positive", "exactly"]
    uncertain_words = ["maybe", "perhaps", "possibly", "might", "could", "think", "believe", "guess", "not sure", "i don't know"]
    hedge_words = ["sort of", "kind of", "somewhat", "probably", "likely", "apparently"]
    certain_count = sum(1 for w in words if w in certain_words)
    uncertain_count = sum(text.count(p) for p in uncertain_words)
    hedge_count = sum(text.count(p) for p in hedge_words)

    # Detail level
    specific_markers = ["on", "at", "exactly", "approximately", "around", "between"]
    detail_score = min(100, int((sum(1 for w in words if w in specific_markers) / max(total_words, 1)) * 1000))

    # Consistency (self-contradiction signals)
    contradict_signals = ["actually", "i mean", "well actually", "no wait", "i meant", "correction"]
    contradict_count = sum(text.count(p) for p in contradict_signals)

    # Emotional control
    exclamations = text.count("!") + text.count("?!")
    caps_words = sum(1 for w in " ".join(statements).split() if w.isupper() and len(w) > 2)

    # Calculate scores (0-100)
    certainty_score = min(100, max(0, 50 + certain_count * 5 - uncertain_count * 8 - hedge_count * 4))
    consistency_score = max(0, 100 - contradict_count * 15)
    composure_score = max(0, 100 - exclamations * 5 - caps_words * 3)
    detail_final = min(100, detail_score)

    # Overall credibility
    overall = int(certainty_score * 0.25 + consistency_score * 0.30 + composure_score * 0.20 + detail_final * 0.25)

    # Assessment
    if overall >= 80:
        assessment = "High credibility — witness demonstrates strong consistency, certainty, and detailed recall"
    elif overall >= 60:
        assessment = "Moderate credibility — some areas of uncertainty but generally coherent testimony"
    elif overall >= 40:
        assessment = "Mixed credibility — notable inconsistencies or uncertainty patterns detected"
    else:
        assessment = "Low credibility — significant concerns with consistency, certainty, or detail level"

    # Red flags
    red_flags = []
    if uncertain_count > 5:
        red_flags.append(f"High uncertainty language ({uncertain_count} instances)")
    if contradict_count > 3:
        red_flags.append(f"Self-corrections detected ({contradict_count} instances)")
    if hedge_count > 4:
        red_flags.append(f"Excessive hedging ({hedge_count} instances)")
    if exclamations > 5:
        red_flags.append(f"Emotional outbursts ({exclamations} instances)")

    # Strengths
    strengths = []
    if certain_count > 3:
        strengths.append(f"Strong certainty language ({certain_count} instances)")
    if consistency_score > 80:
        strengths.append("High internal consistency")
    if detail_final > 60:
        strengths.append("Good level of specific detail")
    if composure_score > 80:
        strengths.append("Maintains emotional composure")

    return {
        "overall_score": overall,
        "assessment": assessment,
        "scores": {
            "certainty": certainty_score,
            "consistency": consistency_score,
            "composure": composure_score,
            "detail_level": detail_final,
        },
        "red_flags": red_flags,
        "strengths": strengths,
        "language_stats": {
            "certain_words": certain_count,
            "uncertain_words": uncertain_count,
            "hedge_words": hedge_count,
            "self_corrections": contradict_count,
            "total_words_analyzed": total_words,
        },
        "statement_count": len(statements),
    }


# ── Testimony Word Cloud Data ───────────────────
@router.get("/sessions/{session_id}/wordcloud-data")
async def wordcloud_data(session_id: str):
    """Generate word frequency data for word cloud visualization."""
    session = await firestore_service.get_session(session_id)
    if not session:
        raise HTTPException(status_code=404, detail="Session not found")

    statements = []
    if hasattr(session, "messages"):
        for m in session.messages:
            role = m.get("role", "") if isinstance(m, dict) else getattr(m, "role", "")
            content = m.get("content", "") if isinstance(m, dict) else getattr(m, "content", "")
            if role == "user" and len(content) > 10:
                statements.append(content)

    text = " ".join(statements).lower()
    # Remove punctuation
    clean = re.sub(r'[^\w\s]', '', text)
    words = clean.split()

    # Stop words
    stop_words = {"the", "a", "an", "and", "or", "but", "in", "on", "at", "to", "for",
                  "of", "with", "by", "from", "is", "was", "were", "are", "been", "be",
                  "have", "has", "had", "do", "does", "did", "will", "would", "could",
                  "should", "may", "might", "shall", "can", "it", "its", "this", "that",
                  "these", "those", "i", "me", "my", "we", "our", "you", "your", "he",
                  "she", "him", "her", "his", "they", "them", "their", "not", "no", "yes",
                  "so", "if", "then", "than", "just", "very", "also", "about", "up", "out",
                  "there", "here", "when", "where", "what", "which", "who", "how", "all",
                  "each", "every", "some", "any", "as", "into", "through", "during", "before",
                  "after", "above", "below", "between", "same", "other", "such", "only", "own",
                  "too", "more", "most", "much", "many", "well", "back", "over", "like", "dont",
                  "didnt", "im", "ive", "thats", "its", "was", "going", "know", "think", "said"}

    freq = {}
    for w in words:
        if len(w) > 2 and w not in stop_words:
            freq[w] = freq.get(w, 0) + 1

    sorted_words = sorted(freq.items(), key=lambda x: x[1], reverse=True)
    top_words = [{"word": w, "count": c, "size": min(100, max(12, c * 8))} for w, c in sorted_words[:80]]

    # Categorize top words
    legal_terms = {"testimony", "witness", "evidence", "statement", "deposition", "court",
                   "attorney", "counsel", "objection", "sustained", "overruled", "plaintiff",
                   "defendant", "sworn", "oath", "exhibit", "prosecution", "defense", "verdict",
                   "judge", "jury", "trial", "hearing", "motion", "stipulate"}
    time_words = {"morning", "afternoon", "evening", "night", "day", "week", "month", "year",
                  "today", "yesterday", "tomorrow", "monday", "tuesday", "wednesday", "thursday",
                  "friday", "saturday", "sunday", "january", "february", "march"}
    people_words = {"mr", "mrs", "ms", "dr", "sir", "maam"}

    categories = {"legal": 0, "temporal": 0, "people": 0, "general": 0}
    for w, c in sorted_words[:50]:
        if w in legal_terms:
            categories["legal"] += c
        elif w in time_words:
            categories["temporal"] += c
        elif w in people_words:
            categories["people"] += c
        else:
            categories["general"] += c

    return {
        "words": top_words,
        "total_unique_words": len(freq),
        "total_words": len(words),
        "categories": categories,
        "top_bigrams": _extract_bigrams(words, stop_words)[:20],
    }


def _extract_bigrams(words, stop_words):
    bigrams = {}
    for i in range(len(words) - 1):
        if words[i] not in stop_words and words[i+1] not in stop_words and len(words[i]) > 2 and len(words[i+1]) > 2:
            bg = f"{words[i]} {words[i+1]}"
            bigrams[bg] = bigrams.get(bg, 0) + 1
    return [{"phrase": p, "count": c} for p, c in sorted(bigrams.items(), key=lambda x: x[1], reverse=True)]


# ── Deposition Cost Calculator ───────────────────
@router.get("/sessions/{session_id}/depo-cost")
async def deposition_cost_estimate(session_id: str):
    """Estimate deposition costs based on testimony content."""
    session = await firestore_service.get_session(session_id)
    if not session:
        raise HTTPException(status_code=404, detail="Session not found")

    statements = []
    if hasattr(session, "messages"):
        for m in session.messages:
            content = m.get("content", "") if isinstance(m, dict) else getattr(m, "content", "")
            if len(content) > 10:
                statements.append(content)

    full_text = " ".join(statements)
    words = full_text.split()
    total_words = len(words)
    pages = max(1, total_words // 250)
    hours = max(0.5, total_words / 9000)  # ~150 words/min speaking rate

    # Cost estimates (typical US rates)
    court_reporter_per_page = 6.50
    court_reporter_appearance = 350
    videographer_per_hour = 150
    videographer_appearance = 250
    transcript_per_page = 4.50
    exhibit_per_page = 1.50

    # Estimate exhibits
    exhibit_count = full_text.lower().count("exhibit") + full_text.lower().count("document") // 2
    exhibit_pages = exhibit_count * 3

    costs = {
        "court_reporter": {
            "appearance_fee": court_reporter_appearance,
            "per_page_fee": round(pages * court_reporter_per_page, 2),
            "subtotal": round(court_reporter_appearance + pages * court_reporter_per_page, 2),
        },
        "videographer": {
            "appearance_fee": videographer_appearance,
            "hourly_fee": round(hours * videographer_per_hour, 2),
            "subtotal": round(videographer_appearance + hours * videographer_per_hour, 2),
        },
        "transcript": {
            "original_per_page": round(pages * transcript_per_page, 2),
            "copy_per_page": round(pages * 1.50, 2),
            "expedited_surcharge": round(pages * 2.00, 2) if pages > 100 else 0,
            "subtotal": round(pages * transcript_per_page + pages * 1.50, 2),
        },
        "exhibits": {
            "estimated_exhibits": exhibit_count,
            "exhibit_pages": exhibit_pages,
            "exhibit_cost": round(exhibit_pages * exhibit_per_page, 2),
        },
    }

    total = round(
        costs["court_reporter"]["subtotal"]
        + costs["videographer"]["subtotal"]
        + costs["transcript"]["subtotal"]
        + costs["exhibits"]["exhibit_cost"],
        2,
    )

    return {
        "estimated_total": total,
        "breakdown": costs,
        "deposition_stats": {
            "estimated_pages": pages,
            "estimated_hours": round(hours, 1),
            "total_words": total_words,
            "estimated_exhibits": exhibit_count,
        },
        "notes": [
            "Estimates based on average US metropolitan rates",
            "Actual costs vary by jurisdiction and provider",
            "Does not include attorney fees or travel expenses",
            "Expedited transcript surcharges apply for 100+ pages",
        ],
    }


# ── Testimony Readability Score ───────────────────
@router.get("/sessions/{session_id}/readability")
async def testimony_readability(session_id: str):
    """Calculate readability metrics for testimony text."""
    session = await firestore_service.get_session(session_id)
    if not session:
        raise HTTPException(status_code=404, detail="Session not found")

    statements = []
    if hasattr(session, "messages"):
        for m in session.messages:
            role = m.get("role", "") if isinstance(m, dict) else getattr(m, "role", "")
            content = m.get("content", "") if isinstance(m, dict) else getattr(m, "content", "")
            if role == "user" and len(content) > 15:
                statements.append(content)

    text = " ".join(statements)
    sentences = re.split(r'[.!?]+', text)
    sentences = [s.strip() for s in sentences if len(s.strip()) > 3]
    words = text.split()
    total_words = len(words)
    total_sentences = max(1, len(sentences))

    def count_syllables(word):
        word = word.lower().strip(".,!?;:")
        if len(word) <= 2:
            return 1
        count = 0
        vowels = "aeiouy"
        prev_vowel = False
        for ch in word:
            if ch in vowels:
                if not prev_vowel:
                    count += 1
                prev_vowel = True
            else:
                prev_vowel = False
        if word.endswith("e") and count > 1:
            count -= 1
        return max(1, count)

    total_syllables = sum(count_syllables(w) for w in words)
    complex_words = sum(1 for w in words if count_syllables(w) >= 3)
    avg_word_len = sum(len(w) for w in words) / max(total_words, 1)
    avg_sentence_len = total_words / total_sentences

    # Flesch Reading Ease
    flesch = 206.835 - 1.015 * avg_sentence_len - 84.6 * (total_syllables / max(total_words, 1))
    flesch = max(0, min(100, round(flesch, 1)))

    # Flesch-Kincaid Grade Level
    fk_grade = 0.39 * avg_sentence_len + 11.8 * (total_syllables / max(total_words, 1)) - 15.59
    fk_grade = max(0, round(fk_grade, 1))

    # Gunning Fog Index
    fog = 0.4 * (avg_sentence_len + 100 * (complex_words / max(total_words, 1)))
    fog = max(0, round(fog, 1))

    # Coleman-Liau Index
    L = (avg_word_len * 100) / max(total_words, 1) * total_words
    S = (total_sentences / max(total_words, 1)) * 100
    cli = 0.0588 * (sum(len(w) for w in words) / max(total_words, 1) * 100) - 0.296 * S - 15.8
    cli = max(0, round(cli, 1))

    # Interpretation
    if flesch >= 80:
        reading_level = "Very Easy"
        audience = "Elementary school level — simple, clear testimony"
    elif flesch >= 60:
        reading_level = "Standard"
        audience = "8th-9th grade level — typical conversational testimony"
    elif flesch >= 40:
        reading_level = "Somewhat Difficult"
        audience = "College level — uses technical or legal language"
    elif flesch >= 20:
        reading_level = "Difficult"
        audience = "Graduate level — dense, complex testimony"
    else:
        reading_level = "Very Difficult"
        audience = "Professional level — highly technical/legal content"

    return {
        "scores": {
            "flesch_reading_ease": flesch,
            "flesch_kincaid_grade": fk_grade,
            "gunning_fog_index": fog,
            "coleman_liau_index": cli,
        },
        "interpretation": {
            "reading_level": reading_level,
            "audience": audience,
            "grade_level": fk_grade,
        },
        "text_stats": {
            "total_words": total_words,
            "total_sentences": total_sentences,
            "total_syllables": total_syllables,
            "complex_words": complex_words,
            "avg_word_length": round(avg_word_len, 1),
            "avg_sentence_length": round(avg_sentence_len, 1),
        },
        "statement_count": len(statements),
    }


# ── Key Date Extractor ───────────────────
@router.get("/sessions/{session_id}/keydates")
async def extract_key_dates(session_id: str):
    """Extract all dates and temporal references from testimony."""
    session = await firestore_service.get_session(session_id)
    if not session:
        raise HTTPException(status_code=404, detail="Session not found")

    statements = []
    if hasattr(session, "messages"):
        for m in session.messages:
            role = m.get("role", "") if isinstance(m, dict) else getattr(m, "role", "")
            content = m.get("content", "") if isinstance(m, dict) else getattr(m, "content", "")
            if role == "user" and len(content) > 10:
                statements.append(content)

    text = " ".join(statements)
    dates_found = []

    # Pattern: MM/DD/YYYY or MM-DD-YYYY
    for match in re.finditer(r'\b(\d{1,2}[/-]\d{1,2}[/-]\d{2,4})\b', text):
        dates_found.append({"date": match.group(1), "format": "numeric", "context": _get_context(text, match.start())})

    # Pattern: Month DD, YYYY
    months = "January|February|March|April|May|June|July|August|September|October|November|December"
    for match in re.finditer(rf'\b({months})\s+(\d{{1,2}}),?\s*(\d{{4}})?\b', text, re.IGNORECASE):
        date_str = match.group(0)
        dates_found.append({"date": date_str, "format": "written", "context": _get_context(text, match.start())})

    # Pattern: "last Monday", "next week", relative dates
    relative_patterns = [
        (r'\b(last|next|this)\s+(monday|tuesday|wednesday|thursday|friday|saturday|sunday|week|month|year)\b', "relative_day"),
        (r'\b(\d+)\s+(days?|weeks?|months?|years?)\s+(ago|later|before|after)\b', "relative_duration"),
        (r'\b(yesterday|today|tomorrow|the day before|the day after|that morning|that evening|that night|that afternoon)\b', "relative_reference"),
    ]
    for pattern, ptype in relative_patterns:
        for match in re.finditer(pattern, text, re.IGNORECASE):
            dates_found.append({"date": match.group(0), "format": ptype, "context": _get_context(text, match.start())})

    # Pattern: time references
    times_found = []
    for match in re.finditer(r'\b(\d{1,2}:\d{2}\s*(?:am|pm|AM|PM)?)\b', text):
        times_found.append({"time": match.group(1), "context": _get_context(text, match.start())})
    for match in re.finditer(r'\b(\d{1,2}\s*(?:am|pm|AM|PM|a\.m\.|p\.m\.))\b', text):
        times_found.append({"time": match.group(1), "context": _get_context(text, match.start())})

    # Sequence words
    sequence_words = []
    seq_patterns = ["first", "then", "next", "after that", "before that", "later", "earlier",
                    "subsequently", "previously", "finally", "at that point", "meanwhile"]
    for pat in seq_patterns:
        count = text.lower().count(pat)
        if count > 0:
            sequence_words.append({"word": pat, "occurrences": count})

    return {
        "dates": dates_found[:50],
        "times": times_found[:30],
        "sequence_markers": sorted(sequence_words, key=lambda x: x["occurrences"], reverse=True),
        "summary": {
            "total_dates": len(dates_found),
            "total_times": len(times_found),
            "date_formats": {"numeric": sum(1 for d in dates_found if d["format"] == "numeric"),
                            "written": sum(1 for d in dates_found if d["format"] == "written"),
                            "relative": sum(1 for d in dates_found if d["format"].startswith("relative"))},
        },
        "statement_count": len(statements),
    }


def _get_context(text, pos, window=60):
    start = max(0, pos - window)
    end = min(len(text), pos + window)
    ctx = text[start:end].strip()
    if start > 0:
        ctx = "..." + ctx
    if end < len(text):
        ctx = ctx + "..."
    return ctx


# ── Admin Endpoint Usage Trends ───────────────────
_usage_history = deque(maxlen=5000)

def _track_usage_history(endpoint: str):
    _usage_history.append({
        "endpoint": endpoint,
        "timestamp": datetime.now(timezone.utc).isoformat(),
    })

@router.get("/admin/usage-trends")
async def get_usage_trends(hours: int = 24, auth=Depends(require_admin_auth)):
    """Track endpoint usage over time with trends."""
    _log_admin_action("view_usage_trends", "Viewed usage trends")
    now = datetime.now(timezone.utc)
    cutoff = now - __import__("datetime").timedelta(hours=hours)

    # Group by hour
    hourly = {}
    endpoint_counts = {}
    for entry in _usage_history:
        try:
            ts = datetime.fromisoformat(entry["timestamp"])
            if ts >= cutoff:
                hour_key = ts.strftime("%Y-%m-%d %H:00")
                hourly[hour_key] = hourly.get(hour_key, 0) + 1
                ep = entry["endpoint"]
                endpoint_counts[ep] = endpoint_counts.get(ep, 0) + 1
        except Exception:
            continue

    # Sort hourly data
    sorted_hours = sorted(hourly.items())
    top_endpoints = sorted(endpoint_counts.items(), key=lambda x: x[1], reverse=True)[:15]

    # Calculate trend
    if len(sorted_hours) >= 2:
        first_half = sum(v for _, v in sorted_hours[:len(sorted_hours)//2])
        second_half = sum(v for _, v in sorted_hours[len(sorted_hours)//2:])
        if first_half > 0:
            trend_pct = round(((second_half - first_half) / first_half) * 100, 1)
        else:
            trend_pct = 0
        trend = "increasing" if trend_pct > 10 else "decreasing" if trend_pct < -10 else "stable"
    else:
        trend_pct = 0
        trend = "insufficient_data"

    return {
        "period_hours": hours,
        "total_requests": len([e for e in _usage_history if True]),
        "hourly_data": [{"hour": h, "requests": c} for h, c in sorted_hours],
        "top_endpoints": [{"endpoint": ep, "requests": c} for ep, c in top_endpoints],
        "trend": {
            "direction": trend,
            "change_percent": trend_pct,
        },
    }


# ── Admin Session Search ───────────────────
@router.get("/admin/session-search")
async def admin_session_search(q: str = "", auth=Depends(require_admin_auth)):
    """Search sessions by content, title, or metadata."""
    _log_admin_action("session_search", f"Searched sessions: {q}")
    sessions = await firestore_service.list_sessions(limit=500)
    query = q.lower().strip()

    results = []
    for s in sessions:
        title = getattr(s, "title", "") or ""
        session_id = getattr(s, "id", "") or ""
        created = getattr(s, "created_at", "") or ""
        messages = getattr(s, "messages", []) or []

        # Search in title
        if query in title.lower():
            results.append({
                "id": session_id,
                "title": title,
                "created_at": str(created),
                "match_type": "title",
                "message_count": len(messages),
            })
            continue

        # Search in message content
        for m in messages:
            content = m.get("content", "") if isinstance(m, dict) else getattr(m, "content", "")
            if query and query in content.lower():
                snippet_idx = content.lower().index(query)
                snippet_start = max(0, snippet_idx - 40)
                snippet_end = min(len(content), snippet_idx + len(query) + 40)
                snippet = content[snippet_start:snippet_end]
                if snippet_start > 0:
                    snippet = "..." + snippet
                if snippet_end < len(content):
                    snippet += "..."
                results.append({
                    "id": session_id,
                    "title": title,
                    "created_at": str(created),
                    "match_type": "content",
                    "snippet": snippet,
                    "message_count": len(messages),
                })
                break

    return {
        "query": q,
        "total_results": len(results),
        "results": results[:50],
    }


# ── Sentiment Timeline (Enhanced) ──────────────────────────────
@router.get("/sessions/{session_id}/sentiment-analysis")
async def sentiment_analysis(session_id: str):
    """Analyze emotional sentiment shifts across testimony segments."""
    session = await firestore_service.get_session(session_id)
    if not session:
        raise HTTPException(status_code=404, detail="Session not found")

    statements = []
    if hasattr(session, "messages"):
        for m in session.messages:
            role = m.get("role", "") if isinstance(m, dict) else getattr(m, "role", "")
            content = m.get("content", "") if isinstance(m, dict) else getattr(m, "content", "")
            if role == "user" and len(content) > 10:
                statements.append(content)

    positive_words = {"yes", "agree", "correct", "absolutely", "certainly", "sure", "clearly", "good",
                      "happy", "pleased", "willing", "cooperative", "truthful", "honest", "fair",
                      "comfortable", "confident", "positive", "helpful", "remember", "exactly"}
    negative_words = {"no", "disagree", "wrong", "never", "not", "deny", "refuse", "hostile",
                      "angry", "upset", "confused", "scared", "afraid", "worried", "nervous",
                      "uncomfortable", "reluctant", "unsure", "uncertain", "forget", "mistake",
                      "lie", "false", "misrepresent", "mislead", "threat", "harm"}
    hedging_words = {"maybe", "perhaps", "possibly", "might", "could", "somewhat", "kind of",
                     "sort of", "i think", "i believe", "i guess", "not sure", "probably",
                     "approximately", "around", "about", "roughly", "generally"}

    timeline_segments = []
    for idx, stmt in enumerate(statements):
        words = stmt.lower().split()
        word_set = set(words)
        text_lower = stmt.lower()

        pos_count = len(word_set & positive_words)
        neg_count = len(word_set & negative_words)
        hedge_count = sum(1 for h in hedging_words if h in text_lower)
        total = pos_count + neg_count + hedge_count or 1

        pos_pct = round(pos_count / total * 100)
        neg_pct = round(neg_count / total * 100)
        hedge_pct = round(hedge_count / total * 100)

        if pos_pct > neg_pct and pos_pct > hedge_pct:
            mood = "positive"
        elif neg_pct > pos_pct and neg_pct > hedge_pct:
            mood = "negative"
        elif hedge_pct > pos_pct and hedge_pct > neg_pct:
            mood = "hedging"
        else:
            mood = "neutral"

        score = round((pos_count - neg_count) / total * 100)

        timeline_segments.append({
            "segment": idx + 1,
            "mood": mood,
            "score": score,
            "positive": pos_count,
            "negative": neg_count,
            "hedging": hedge_count,
            "word_count": len(words),
            "preview": stmt[:80] + ("..." if len(stmt) > 80 else "")
        })

    moods = [s["mood"] for s in timeline_segments]
    shifts = sum(1 for i in range(1, len(moods)) if moods[i] != moods[i - 1])
    avg_score = round(sum(s["score"] for s in timeline_segments) / max(len(timeline_segments), 1))
    dominant = max(set(moods), key=moods.count) if moods else "none"

    return {
        "segments": timeline_segments,
        "summary": {
            "total_segments": len(timeline_segments),
            "mood_shifts": shifts,
            "average_score": avg_score,
            "dominant_mood": dominant,
            "mood_distribution": {m: moods.count(m) for m in set(moods)} if moods else {}
        }
    }


# ── Objection Pattern Analyzer ─────────────────────────────────
@router.get("/sessions/{session_id}/objections")
async def analyze_objections(session_id: str):
    """Detect and categorize objection patterns in deposition text."""
    session = await firestore_service.get_session(session_id)
    if not session:
        raise HTTPException(status_code=404, detail="Session not found")

    statements = []
    if hasattr(session, "messages"):
        for m in session.messages:
            content = m.get("content", "") if isinstance(m, dict) else getattr(m, "content", "")
            if len(content) > 5:
                statements.append(content)

    text = " ".join(statements)
    text_lower = text.lower()

    objection_types = {
        "relevance": [r'\bobjection[,:]?\s*relevan', r'\bnot relevant\b', r'\birrelevant\b'],
        "hearsay": [r'\bobjection[,:]?\s*hearsay\b', r'\bhearsay\b', r'\bout[- ]of[- ]court statement\b'],
        "leading": [r'\bobjection[,:]?\s*leading\b', r'\bleading question\b', r'\bleads the witness\b'],
        "speculation": [r'\bobjection[,:]?\s*speculat', r'\bcalls for speculation\b', r'\bspeculative\b'],
        "foundation": [r'\bobjection[,:]?\s*foundation\b', r'\blacks foundation\b', r'\bno foundation\b'],
        "compound": [r'\bobjection[,:]?\s*compound\b', r'\bcompound question\b'],
        "argumentative": [r'\bobjection[,:]?\s*argumentative\b', r'\bargumentative\b'],
        "asked_and_answered": [r'\basked and answered\b', r'\balready answered\b'],
        "vague": [r'\bobjection[,:]?\s*vague\b', r'\bvague and ambiguous\b'],
        "form": [r'\bobjection[,:]?\s*form\b', r'\bobjection as to form\b']
    }

    objections_found = []
    for obj_type, patterns in objection_types.items():
        count = 0
        for pat in patterns:
            count += len(re.findall(pat, text_lower))
        if count > 0:
            objections_found.append({"type": obj_type, "count": count})

    sustained = len(re.findall(r'\bsustained\b', text_lower))
    overruled = len(re.findall(r'\boverruled\b', text_lower))
    total_obj = sum(o["count"] for o in objections_found)

    objections_found.sort(key=lambda x: x["count"], reverse=True)

    return {
        "objections": objections_found,
        "rulings": {
            "sustained": sustained,
            "overruled": overruled,
            "success_rate": round(sustained / max(sustained + overruled, 1) * 100)
        },
        "total_objections": total_obj,
        "most_common": objections_found[0]["type"] if objections_found else "none",
        "contentiousness": "high" if total_obj > 10 else "moderate" if total_obj > 3 else "low"
    }


# ── Impeachment Material Finder ────────────────────────────────
@router.get("/sessions/{session_id}/impeachment")
async def find_impeachment_material(session_id: str):
    """Identify potential impeachment points in testimony."""
    session = await firestore_service.get_session(session_id)
    if not session:
        raise HTTPException(status_code=404, detail="Session not found")

    statements = []
    if hasattr(session, "messages"):
        for m in session.messages:
            role = m.get("role", "") if isinstance(m, dict) else getattr(m, "role", "")
            content = m.get("content", "") if isinstance(m, dict) else getattr(m, "content", "")
            if role == "user" and len(content) > 10:
                statements.append(content)

    text_lower = " ".join(statements).lower()

    materials = []

    # Prior inconsistent statements
    inconsistency_markers = [
        (r'\bi (?:previously|earlier|before) (?:said|stated|testified|mentioned)\b', "prior_statement"),
        (r'\bthat\'?s not (?:what|how) i (?:said|meant|stated)\b', "correction"),
        (r'\bi (?:don\'?t|do not) recall (?:saying|stating)\b', "memory_gap"),
        (r'\bi (?:may have|might have|could have) (?:said|stated)\b', "hedged_prior"),
        (r'\bcontrary to (?:what|my)\b', "contradiction_admission"),
        (r'\bi (?:was wrong|was mistaken|misspoke)\b', "self_correction")
    ]
    for pat, cat in inconsistency_markers:
        for match in re.finditer(pat, text_lower):
            materials.append({
                "type": "inconsistency",
                "category": cat,
                "text": match.group(0),
                "severity": "high"
            })

    # Bias indicators
    bias_markers = [
        (r'\bi (?:hate|despise|can\'?t stand|dislike)\b', "personal_animosity"),
        (r'\b(?:they|he|she) (?:always|never)\b', "absolute_bias"),
        (r'\bi (?:was told|was asked) to (?:say|testify|state)\b', "coached"),
        (r'\bfinancial (?:interest|stake|incentive|benefit)\b', "financial_motive"),
        (r'\blawsuit|compensation|settlement|payment\b', "litigation_interest"),
        (r'\b(?:friend|relative|family|related to)\b', "relationship_bias")
    ]
    for pat, cat in bias_markers:
        for match in re.finditer(pat, text_lower):
            materials.append({
                "type": "bias",
                "category": cat,
                "text": match.group(0),
                "severity": "medium"
            })

    # Memory/perception issues
    perception_markers = [
        (r'\bi (?:couldn\'?t|could not|can\'?t|cannot) (?:see|hear|tell|remember)\b', "perception_limit"),
        (r'\bit was (?:dark|foggy|raining|loud|noisy|far away)\b', "environmental"),
        (r'\bi (?:was|had been) (?:drinking|intoxicated|medicated|tired|sleepy)\b', "impairment"),
        (r'\bi\'?m not (?:sure|certain|positive|100)\b', "uncertainty"),
        (r'\beverything happened (?:so fast|quickly|in a blur)\b', "temporal_distortion")
    ]
    for pat, cat in perception_markers:
        for match in re.finditer(pat, text_lower):
            materials.append({
                "type": "perception",
                "category": cat,
                "text": match.group(0),
                "severity": "medium"
            })

    by_type = {}
    for m in materials:
        by_type.setdefault(m["type"], []).append(m)
    high_count = sum(1 for m in materials if m["severity"] == "high")

    return {
        "materials": materials[:50],
        "by_type": {k: len(v) for k, v in by_type.items()},
        "total_findings": len(materials),
        "high_severity_count": high_count,
        "impeachment_potential": "strong" if high_count > 3 else "moderate" if len(materials) > 3 else "weak"
    }


# ── Legal Citation Extractor ───────────────────────────────────
@router.get("/sessions/{session_id}/legal-citations")
async def extract_legal_citations(session_id: str):
    """Extract references to laws, cases, statutes, and regulations."""
    session = await firestore_service.get_session(session_id)
    if not session:
        raise HTTPException(status_code=404, detail="Session not found")

    statements = []
    if hasattr(session, "messages"):
        for m in session.messages:
            content = m.get("content", "") if isinstance(m, dict) else getattr(m, "content", "")
            if len(content) > 5:
                statements.append(content)

    text = " ".join(statements)

    citations = []

    # Case citations: Smith v. Jones, Roe v. Wade style
    for match in re.finditer(r'\b([A-Z][a-zA-Z\']+(?:\s+(?:et al\.?)?)?)\s+v\.?\s+([A-Z][a-zA-Z\']+(?:\s+(?:et al\.?)?)?)(?:,?\s*(\d{2,4}\s*[A-Z][a-zA-Z.]*\s*\d+))?\b', text):
        citations.append({
            "type": "case_law",
            "citation": match.group(0).strip(),
            "parties": f"{match.group(1).strip()} v. {match.group(2).strip()}"
        })

    # U.S. Code: 42 U.S.C. § 1983
    for match in re.finditer(r'\b(\d+)\s*(U\.?S\.?C\.?|USC)\s*[§]?\s*(\d+[a-z]?(?:\(\w+\))*)\b', text):
        citations.append({
            "type": "federal_statute",
            "citation": match.group(0).strip(),
            "title": match.group(1),
            "section": match.group(3)
        })

    # State statutes
    for match in re.finditer(r'\b(?:Section|§|sec\.?)\s*(\d+[\w.-]*)\b', text, re.IGNORECASE):
        citations.append({
            "type": "statute_section",
            "citation": match.group(0).strip(),
            "section": match.group(1)
        })

    # Federal Rules references
    for match in re.finditer(r'\b(?:Rule|FRE|FRCP|FRCrP)\s*(\d+(?:\.\d+)?(?:\([a-z]\))*)\b', text, re.IGNORECASE):
        citations.append({
            "type": "rule",
            "citation": match.group(0).strip(),
            "rule_number": match.group(1)
        })

    # Regulation references: CFR
    for match in re.finditer(r'\b(\d+)\s*(?:C\.?F\.?R\.?|CFR)\s*(?:Part|§)?\s*(\d+[\w.]*)\b', text):
        citations.append({
            "type": "regulation",
            "citation": match.group(0).strip(),
            "title": match.group(1),
            "part": match.group(2)
        })

    # Amendment references
    for match in re.finditer(r'\b(?:First|Second|Third|Fourth|Fifth|Sixth|Seventh|Eighth|Ninth|Tenth|Fourteenth|\d+(?:st|nd|rd|th))\s+Amendment\b', text, re.IGNORECASE):
        citations.append({
            "type": "constitutional",
            "citation": match.group(0).strip()
        })

    # Dedup by citation text
    seen = set()
    unique = []
    for c in citations:
        key = c["citation"].lower()
        if key not in seen:
            seen.add(key)
            unique.append(c)

    by_type = {}
    for c in unique:
        by_type.setdefault(c["type"], []).append(c)

    return {
        "citations": unique[:50],
        "by_type": {k: len(v) for k, v in by_type.items()},
        "total_citations": len(unique),
        "most_cited_type": max(by_type.keys(), key=lambda k: len(by_type[k])) if by_type else "none"
    }


# ── Testimony Comparison ───────────────────────────────────────
@router.get("/sessions/{session_id}/compare/{other_id}")
async def compare_testimonies(session_id: str, other_id: str):
    """Compare two testimony sessions for overlaps and contradictions."""
    session_a = await firestore_service.get_session(session_id)
    if not session_a:
        raise HTTPException(status_code=404, detail="Session A not found")
    session_b = await firestore_service.get_session(other_id)
    if not session_b:
        raise HTTPException(status_code=404, detail="Session B not found")

    def extract_statements(session):
        stmts = []
        if hasattr(session, "messages"):
            for m in session.messages:
                role = m.get("role", "") if isinstance(m, dict) else getattr(m, "role", "")
                content = m.get("content", "") if isinstance(m, dict) else getattr(m, "content", "")
                if role == "user" and len(content) > 10:
                    stmts.append(content)
        return stmts

    stmts_a = extract_statements(session_a)
    stmts_b = extract_statements(session_b)
    text_a = " ".join(stmts_a).lower()
    text_b = " ".join(stmts_b).lower()

    words_a = set(re.findall(r'\b[a-z]{3,}\b', text_a))
    words_b = set(re.findall(r'\b[a-z]{3,}\b', text_b))
    stop = {"the", "and", "was", "that", "this", "with", "for", "are", "but", "not", "you",
            "all", "can", "had", "her", "his", "one", "our", "out", "has", "have", "from",
            "they", "been", "said", "each", "she", "which", "their", "will", "other", "about",
            "them", "then", "than", "into", "could", "would", "there", "what", "when", "your"}
    words_a -= stop
    words_b -= stop

    shared = words_a & words_b
    unique_a = words_a - words_b
    unique_b = words_b - words_a
    overlap_pct = round(len(shared) / max(len(words_a | words_b), 1) * 100)

    # Key entity overlap
    def extract_caps(text):
        return set(re.findall(r'\b[A-Z][a-z]+(?:\s+[A-Z][a-z]+)*\b', text))
    entities_a = extract_caps(" ".join(stmts_a))
    entities_b = extract_caps(" ".join(stmts_b))
    shared_entities = entities_a & entities_b

    # Potential contradictions (opposite sentiments on same topics)
    contradictions = []
    topics = list(shared)[:20]
    for topic in topics:
        in_a = any(topic in s.lower() for s in stmts_a)
        in_b = any(topic in s.lower() for s in stmts_b)
        if in_a and in_b:
            context_a = next((s[:100] for s in stmts_a if topic in s.lower()), "")
            context_b = next((s[:100] for s in stmts_b if topic in s.lower()), "")
            if context_a and context_b:
                a_neg = any(w in context_a.lower() for w in ["not", "never", "no", "didn't", "deny"])
                b_neg = any(w in context_b.lower() for w in ["not", "never", "no", "didn't", "deny"])
                if a_neg != b_neg:
                    contradictions.append({
                        "topic": topic,
                        "session_a": context_a,
                        "session_b": context_b
                    })

    title_a = getattr(session_a, "title", session_id[:8])
    title_b = getattr(session_b, "title", other_id[:8])

    return {
        "session_a": {"id": session_id, "title": title_a, "statements": len(stmts_a)},
        "session_b": {"id": other_id, "title": title_b, "statements": len(stmts_b)},
        "vocabulary_overlap": f"{overlap_pct}%",
        "shared_words": len(shared),
        "unique_to_a": len(unique_a),
        "unique_to_b": len(unique_b),
        "shared_entities": list(shared_entities)[:20],
        "potential_contradictions": contradictions[:10],
        "agreement_level": "high" if overlap_pct > 60 else "moderate" if overlap_pct > 30 else "low"
    }


# ── Admin Data Export ──────────────────────────────────────────
@router.get("/admin/data-export")
async def admin_data_export(export_type: str = "sessions", fmt: str = "json", auth=Depends(require_admin_auth)):
    """Export admin data as JSON or CSV."""
    import csv
    import io

    if export_type == "sessions":
        sessions = await firestore_service.list_sessions()
        data = []
        for s in sessions:
            data.append({
                "id": s.id,
                "title": getattr(s, "title", "Untitled"),
                "created_at": str(getattr(s, "created_at", "")),
                "message_count": len(getattr(s, "messages", []))
            })
    elif export_type == "errors":
        data = list(_error_log) if "_error_log" in dir() else []
        if not data:
            try:
                data = list(globals().get("_error_log", []))
            except:
                data = []
    elif export_type == "usage":
        data = []
        uh = globals().get("_usage_history", [])
        for entry in uh:
            data.append({"endpoint": entry.get("endpoint", ""), "timestamp": entry.get("timestamp", "")})
    else:
        raise HTTPException(status_code=400, detail="Invalid export_type. Use: sessions, errors, usage")

    if fmt == "csv" and data:
        output = io.StringIO()
        writer = csv.DictWriter(output, fieldnames=data[0].keys() if data else [])
        writer.writeheader()
        for row in data:
            writer.writerow(row)
        return {"format": "csv", "content": output.getvalue(), "rows": len(data), "export_type": export_type}

    return {"format": "json", "data": data, "rows": len(data), "export_type": export_type}


# ── Admin Rate Limiter ─────────────────────────────────────────
_rate_limit_config = {
    "enabled": True,
    "default_rpm": 60,
    "endpoint_limits": {},
    "blocked_ips": []
}
_rate_tracker = {}

@router.get("/admin/rate-limiter")
async def get_rate_limiter(auth=Depends(require_admin_auth)):
    """Get rate limiter configuration and current status."""
    now = datetime.now()
    window = now - timedelta(minutes=1)

    active_clients = 0
    throttled = 0
    for key, timestamps in _rate_tracker.items():
        recent = [t for t in timestamps if t > window]
        if recent:
            active_clients += 1
            limit = _rate_limit_config["endpoint_limits"].get(key.split(":")[0], _rate_limit_config["default_rpm"])
            if len(recent) >= limit:
                throttled += 1

    return {
        "config": _rate_limit_config,
        "status": {
            "active_clients": active_clients,
            "throttled_clients": throttled,
            "tracking_entries": len(_rate_tracker)
        }
    }

@router.post("/admin/rate-limiter")
async def update_rate_limiter(data: dict, auth=Depends(require_admin_auth)):
    """Update rate limiter configuration."""
    if "enabled" in data:
        _rate_limit_config["enabled"] = bool(data["enabled"])
    if "default_rpm" in data:
        _rate_limit_config["default_rpm"] = max(1, min(1000, int(data["default_rpm"])))
    if "endpoint_limits" in data and isinstance(data["endpoint_limits"], dict):
        _rate_limit_config["endpoint_limits"].update(data["endpoint_limits"])
    if "blocked_ips" in data and isinstance(data["blocked_ips"], list):
        _rate_limit_config["blocked_ips"] = data["blocked_ips"]

    return {"status": "updated", "config": _rate_limit_config}


# ── Witness Stance Tracker ─────────────────────────────────────
@router.get("/sessions/{session_id}/stance")
async def track_witness_stance(session_id: str):
    """Track how a witness's position shifts across topics throughout testimony."""
    session = await firestore_service.get_session(session_id)
    if not session:
        raise HTTPException(status_code=404, detail="Session not found")

    statements = []
    if hasattr(session, "messages"):
        for m in session.messages:
            role = m.get("role", "") if isinstance(m, dict) else getattr(m, "role", "")
            content = m.get("content", "") if isinstance(m, dict) else getattr(m, "content", "")
            if role == "user" and len(content) > 10:
                statements.append(content)

    cooperative_words = {"yes", "agree", "correct", "absolutely", "certainly", "willing",
                         "happy to", "of course", "exactly", "right", "sure", "definitely"}
    evasive_words = {"i don't recall", "i don't remember", "not sure", "possibly",
                     "i can't say", "hard to say", "i think", "maybe", "perhaps",
                     "i believe", "approximately", "i don't know", "not certain"}
    hostile_words = {"no", "never", "refuse", "that's not true", "objection", "won't",
                     "misleading", "mischaracterize", "incorrect", "false", "reject",
                     "absurd", "ridiculous", "inappropriate"}
    assertive_words = {"i know", "i saw", "i remember clearly", "without a doubt",
                       "i'm certain", "i witnessed", "it was", "there's no question",
                       "absolutely certain", "i can confirm", "for a fact"}

    stance_timeline = []
    topic_stances = {}
    for idx, stmt in enumerate(statements):
        lower = stmt.lower()
        words = lower.split()

        coop = sum(1 for w in cooperative_words if w in lower)
        evas = sum(1 for w in evasive_words if w in lower)
        host = sum(1 for w in hostile_words if w in lower)
        asrt = sum(1 for w in assertive_words if w in lower)

        scores = {"cooperative": coop, "evasive": evas, "hostile": host, "assertive": asrt}
        dominant = max(scores, key=scores.get) if any(scores.values()) else "neutral"
        if not any(scores.values()):
            dominant = "neutral"

        # Extract topic keywords
        import re as _re
        topic_words = [w for w in words if len(w) > 5 and w.isalpha()]
        topic = topic_words[0] if topic_words else f"segment_{idx+1}"

        stance_timeline.append({
            "segment": idx + 1,
            "stance": dominant,
            "scores": scores,
            "topic_hint": topic,
            "snippet": stmt[:80] + "..." if len(stmt) > 80 else stmt
        })

        if topic not in topic_stances:
            topic_stances[topic] = []
        topic_stances[topic].append(dominant)

    # Detect stance shifts
    shifts = []
    for i in range(1, len(stance_timeline)):
        if stance_timeline[i]["stance"] != stance_timeline[i-1]["stance"]:
            shifts.append({
                "from_segment": stance_timeline[i-1]["segment"],
                "to_segment": stance_timeline[i]["segment"],
                "from_stance": stance_timeline[i-1]["stance"],
                "to_stance": stance_timeline[i]["stance"]
            })

    stance_counts = {}
    for s in stance_timeline:
        stance_counts[s["stance"]] = stance_counts.get(s["stance"], 0) + 1

    dominant_overall = max(stance_counts, key=stance_counts.get) if stance_counts else "neutral"

    return {
        "session_id": session_id,
        "timeline": stance_timeline,
        "shifts": shifts,
        "total_segments": len(stance_timeline),
        "total_shifts": len(shifts),
        "stance_distribution": stance_counts,
        "dominant_stance": dominant_overall,
        "volatility": "high" if len(shifts) > len(statements) * 0.6 else "moderate" if len(shifts) > len(statements) * 0.3 else "stable"
    }


# ── Testimony Summary Bullets ──────────────────────────────────
@router.get("/sessions/{session_id}/bullets")
async def testimony_bullets(session_id: str):
    """Generate concise bullet-point summary of key testimony points."""
    session = await firestore_service.get_session(session_id)
    if not session:
        raise HTTPException(status_code=404, detail="Session not found")

    statements = []
    if hasattr(session, "messages"):
        for m in session.messages:
            role = m.get("role", "") if isinstance(m, dict) else getattr(m, "role", "")
            content = m.get("content", "") if isinstance(m, dict) else getattr(m, "content", "")
            if role == "user" and len(content) > 15:
                statements.append(content)

    bullets = []
    key_facts = []
    admissions = []
    denials = []

    fact_indicators = {"saw", "witnessed", "observed", "heard", "noticed", "found",
                       "discovered", "confirmed", "verified", "stated", "told", "said"}
    admission_indicators = {"admitted", "acknowledged", "conceded", "agreed", "confirmed",
                            "yes", "correct", "true", "right", "i did"}
    denial_indicators = {"denied", "rejected", "refused", "no", "never", "not true",
                         "false", "incorrect", "didn't", "did not", "wasn't"}

    for idx, stmt in enumerate(statements):
        lower = stmt.lower()
        words = lower.split()

        # Create bullet summary
        sentences = stmt.replace("?", ".").replace("!", ".").split(".")
        first_sentence = sentences[0].strip()
        if len(first_sentence) > 100:
            first_sentence = first_sentence[:97] + "..."

        bullet_type = "statement"
        if any(w in lower for w in admission_indicators):
            bullet_type = "admission"
            admissions.append(first_sentence)
        elif any(w in lower for w in denial_indicators):
            bullet_type = "denial"
            denials.append(first_sentence)
        elif any(w in lower for w in fact_indicators):
            bullet_type = "fact"
            key_facts.append(first_sentence)

        bullets.append({
            "number": idx + 1,
            "type": bullet_type,
            "text": first_sentence,
            "word_count": len(words)
        })

    return {
        "session_id": session_id,
        "title": getattr(session, "title", "Untitled"),
        "bullets": bullets[:50],
        "total_points": len(bullets),
        "key_facts": key_facts[:15],
        "admissions": admissions[:10],
        "denials": denials[:10],
        "summary": {
            "total_statements": len(statements),
            "facts_count": len(key_facts),
            "admissions_count": len(admissions),
            "denials_count": len(denials)
        }
    }


# ── Expert Witness Evaluator ───────────────────────────────────
@router.get("/sessions/{session_id}/expert-eval")
async def evaluate_expert_witness(session_id: str):
    """Evaluate expert witness qualifications and Daubert factors."""
    session = await firestore_service.get_session(session_id)
    if not session:
        raise HTTPException(status_code=404, detail="Session not found")

    statements = []
    if hasattr(session, "messages"):
        for m in session.messages:
            role = m.get("role", "") if isinstance(m, dict) else getattr(m, "role", "")
            content = m.get("content", "") if isinstance(m, dict) else getattr(m, "content", "")
            if role == "user" and len(content) > 10:
                statements.append(content)

    full_text = " ".join(statements).lower()

    # Daubert factors
    qualification_words = {"degree", "ph.d", "phd", "md", "m.d.", "doctorate", "master",
                           "professor", "university", "board certified", "licensed",
                           "credential", "fellowship", "residency", "certification",
                           "published", "peer reviewed", "journal", "research",
                           "training", "experience", "years", "specialty", "expert"}
    methodology_words = {"method", "methodology", "procedure", "protocol", "standard",
                         "technique", "approach", "analysis", "test", "examination",
                         "peer review", "replicated", "validated", "accepted",
                         "scientific", "evidence-based", "clinical"}
    reliability_words = {"error rate", "accuracy", "reliable", "consistent",
                         "reproducible", "standards", "controls", "tested",
                         "verified", "confirmed", "statistically"}
    relevance_words = {"relevant", "applicable", "fits", "pertains", "connected",
                       "related", "applies to", "specific to", "case at hand"}

    qual_score = min(10, sum(2 for w in qualification_words if w in full_text))
    meth_score = min(10, sum(2 for w in methodology_words if w in full_text))
    rel_score = min(10, sum(2 for w in reliability_words if w in full_text))
    rev_score = min(10, sum(2 for w in relevance_words if w in full_text))

    overall = round((qual_score + meth_score + rel_score + rev_score) / 4, 1)

    # Detect qualification mentions
    qualifications_found = [w for w in qualification_words if w in full_text]
    methods_found = [w for w in methodology_words if w in full_text]

    # Vulnerabilities
    vuln = []
    if qual_score < 4:
        vuln.append("Limited qualification evidence in testimony")
    if meth_score < 4:
        vuln.append("Methodology insufficiently described")
    if rel_score < 4:
        vuln.append("Reliability of methods not established")
    if "not sure" in full_text or "i think" in full_text:
        vuln.append("Uncertainty language undermines authority")
    if "first time" in full_text:
        vuln.append("Possible lack of experience in this area")

    strengths = []
    if qual_score >= 7:
        strengths.append("Strong qualification indicators")
    if meth_score >= 7:
        strengths.append("Well-described methodology")
    if "published" in full_text or "peer review" in full_text:
        strengths.append("Published/peer-reviewed work referenced")
    if "board certified" in full_text:
        strengths.append("Board certification mentioned")

    return {
        "session_id": session_id,
        "daubert_scores": {
            "qualifications": qual_score,
            "methodology": meth_score,
            "reliability": rel_score,
            "relevance": rev_score,
            "overall": overall
        },
        "qualifications_found": sorted(set(qualifications_found)),
        "methods_found": sorted(set(methods_found)),
        "vulnerabilities": vuln,
        "strengths": strengths,
        "assessment": "strong" if overall >= 7 else "adequate" if overall >= 4 else "weak",
        "daubert_admissible": overall >= 5
    }


# ── Privilege Log Detector ─────────────────────────────────────
@router.get("/sessions/{session_id}/privileges")
async def detect_privilege_issues(session_id: str):
    """Identify potentially privileged communications in testimony."""
    session = await firestore_service.get_session(session_id)
    if not session:
        raise HTTPException(status_code=404, detail="Session not found")

    statements = []
    if hasattr(session, "messages"):
        for m in session.messages:
            role = m.get("role", "") if isinstance(m, dict) else getattr(m, "role", "")
            content = m.get("content", "") if isinstance(m, dict) else getattr(m, "content", "")
            if role == "user" and len(content) > 10:
                statements.append(content)

    ac_indicators = {"my attorney", "my lawyer", "counsel advised", "legal advice",
                     "attorney-client", "privileged", "i told my lawyer",
                     "my lawyer said", "legal counsel", "attorney told me",
                     "confidential communication", "sought legal advice"}
    wp_indicators = {"work product", "prepared for litigation", "in anticipation",
                     "trial preparation", "attorney work", "mental impressions",
                     "legal strategy", "case theory", "legal memorandum"}
    medical_indicators = {"doctor told me", "my physician", "medical records",
                          "therapy session", "therapist said", "psychiatric",
                          "medical advice", "treatment plan", "diagnosis",
                          "prognosis", "medical history", "health information"}
    spousal_indicators = {"my wife said", "my husband said", "my spouse",
                          "told my wife", "told my husband", "marital communication",
                          "in confidence to my spouse"}

    flags = []
    for idx, stmt in enumerate(statements):
        lower = stmt.lower()
        for indicator in ac_indicators:
            if indicator in lower:
                flags.append({
                    "segment": idx + 1,
                    "type": "attorney_client",
                    "trigger": indicator,
                    "snippet": stmt[:100] + "..." if len(stmt) > 100 else stmt,
                    "severity": "high"
                })
                break
        for indicator in wp_indicators:
            if indicator in lower:
                flags.append({
                    "segment": idx + 1,
                    "type": "work_product",
                    "trigger": indicator,
                    "snippet": stmt[:100] + "..." if len(stmt) > 100 else stmt,
                    "severity": "high"
                })
                break
        for indicator in medical_indicators:
            if indicator in lower:
                flags.append({
                    "segment": idx + 1,
                    "type": "medical",
                    "trigger": indicator,
                    "snippet": stmt[:100] + "..." if len(stmt) > 100 else stmt,
                    "severity": "medium"
                })
                break
        for indicator in spousal_indicators:
            if indicator in lower:
                flags.append({
                    "segment": idx + 1,
                    "type": "spousal",
                    "trigger": indicator,
                    "snippet": stmt[:100] + "..." if len(stmt) > 100 else stmt,
                    "severity": "medium"
                })
                break

    by_type = {}
    for f in flags:
        by_type[f["type"]] = by_type.get(f["type"], 0) + 1

    high_count = sum(1 for f in flags if f["severity"] == "high")

    return {
        "session_id": session_id,
        "flags": flags[:30],
        "by_type": by_type,
        "total_flags": len(flags),
        "high_severity_count": high_count,
        "risk_level": "critical" if high_count > 3 else "elevated" if high_count > 0 else "low" if flags else "none",
        "recommendation": "Review flagged segments with counsel before proceeding" if flags else "No privilege concerns detected"
    }


# ── Testimony Strength Meter ──────────────────────────────────
@router.get("/sessions/{session_id}/strength")
async def measure_testimony_strength(session_id: str):
    """Rate overall testimony strength and trial readiness."""
    session = await firestore_service.get_session(session_id)
    if not session:
        raise HTTPException(status_code=404, detail="Session not found")

    statements = []
    if hasattr(session, "messages"):
        for m in session.messages:
            role = m.get("role", "") if isinstance(m, dict) else getattr(m, "role", "")
            content = m.get("content", "") if isinstance(m, dict) else getattr(m, "content", "")
            if role == "user" and len(content) > 10:
                statements.append(content)

    full_text = " ".join(statements).lower()
    total_words = len(full_text.split())

    # Clarity score (0-10)
    filler_words = {"um", "uh", "like", "you know", "basically", "actually", "i mean",
                    "well", "so", "right", "kind of", "sort of"}
    filler_count = sum(full_text.count(w) for w in filler_words)
    clarity = max(0, min(10, 10 - (filler_count * 2 / max(1, total_words / 100))))

    # Specificity score (0-10)
    specific_indicators = {"date", "time", "location", "address", "number", "name",
                           "exactly", "specifically", "approximately", "at about",
                           "on or around", "i remember", "i saw", "i heard"}
    spec_count = sum(1 for w in specific_indicators if w in full_text)
    specificity = min(10, spec_count * 1.5)

    # Consistency score (0-10)
    contradiction_signals = {"actually", "i mean", "wait", "let me correct",
                             "i misspoke", "that's not what i meant", "sorry"}
    contra_count = sum(full_text.count(w) for w in contradiction_signals)
    consistency = max(0, min(10, 10 - contra_count))

    # Confidence score (0-10)
    confident_words = {"i know", "i'm certain", "absolutely", "definitely", "without doubt",
                       "clearly", "i remember", "i saw", "i confirm"}
    uncertain_words = {"i think", "maybe", "perhaps", "not sure", "i don't recall",
                       "possibly", "i guess", "i believe", "might have"}
    conf_pos = sum(1 for w in confident_words if w in full_text)
    conf_neg = sum(1 for w in uncertain_words if w in full_text)
    confidence = min(10, max(0, 5 + conf_pos * 1.5 - conf_neg * 1.5))

    # Detail score (0-10)
    avg_stmt_len = sum(len(s.split()) for s in statements) / max(1, len(statements))
    detail = min(10, avg_stmt_len / 5)

    overall = round((clarity + specificity + consistency + confidence + detail) / 5, 1)

    strengths = []
    weaknesses = []
    if clarity >= 7: strengths.append("Clear and articulate testimony")
    if clarity < 4: weaknesses.append("Excessive filler words reduce clarity")
    if specificity >= 7: strengths.append("Rich in specific details")
    if specificity < 4: weaknesses.append("Lacks specific details and dates")
    if consistency >= 7: strengths.append("Consistent throughout")
    if consistency < 4: weaknesses.append("Self-corrections suggest inconsistency")
    if confidence >= 7: strengths.append("Projects confidence and certainty")
    if confidence < 4: weaknesses.append("Appears uncertain and hesitant")
    if detail >= 7: strengths.append("Detailed responses")
    if detail < 4: weaknesses.append("Responses are too brief")

    return {
        "session_id": session_id,
        "scores": {
            "clarity": round(clarity, 1),
            "specificity": round(specificity, 1),
            "consistency": round(consistency, 1),
            "confidence": round(confidence, 1),
            "detail": round(detail, 1),
            "overall": overall
        },
        "strengths": strengths,
        "weaknesses": weaknesses,
        "trial_ready": overall >= 6,
        "grade": "A" if overall >= 8 else "B" if overall >= 6 else "C" if overall >= 4 else "D",
        "recommendation": "Strong testimony for trial use" if overall >= 7 else "Consider preparation coaching" if overall >= 4 else "Significant preparation needed"
    }


